request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?idType ?idValue (COUNT(DISTINCT ?gw) AS ?exclusiveGatewayCount)
WHERE {
  VALUES (?idType ?idValue) {
    ("normalized" "2b18c5f00a5a46159c6cb6a3e2bc79e9")
    ("original" "2b18c5f00a5a46159c6cb6a3e2bc79e9")
  }
  ?model a bboExt:Model .
  ?model tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL {
    FILTER(?idType = "normalized")
    ?model tai:normalizedId ?idValue .
  }
  OPTIONAL {
    FILTER(?idType = "original")
    ?model tai:originalId ?idValue .
  }
  FILTER(BOUND(?idValue))

  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?gw a bboExt:ExclusiveGateway ; tai:belongsTo ?choreo . }
}
GROUP BY ?model ?modelName ?idType ?idValue
LIMIT 25
